import React, {useEffect, useState, useRef} from 'react'
import {useParams} from 'react-router-dom'
import {getSingleListing} from '../WebAPI'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import Sidebar from '../components/Sidebar'
import cancel from '../components/static/cancel.png'

const ListingWrapper = styled.div `
display:flex;
width:90%;
justify-content:center;
`

const LeftInfoSection = styled.div `
width:20%;
display:flex;
justify-content:center;
align-items:center;
height:100vh;
`

const ImageSection = styled.div `
width:50%;
`

const Image = styled.img ``

const RightInfoSection = styled.div `
width:30%;
display:flex;
justify-content:center;
align-items:center;
height:100vh;
`

export default function SingleListing () {
	const {id} = useParams()
	const [listingData, setListingData] = useState([])

	useEffect(() => {
		getSingleListing(id, setListingData)
	},[])

	const listingImage = Object.entries(listingData).filter(data => data[0].indexOf('image') >= 0)

	return (
		<>
			<Header />
			<Navbar />
			<ListingWrapper>
				<LeftInfoSection></LeftInfoSection>
				<ImageSection>
					{listingImage.map(image => <Image key={image[0]} src={image[1]} alt={cancel} width='400px' height='600px'/>)}
				</ImageSection>
				<RightInfoSection></RightInfoSection>
			</ListingWrapper>

		</>
	)
}
